  { type: 'uri', value: 'https://example.com', label: 'Visit Site' }
], {class: 'customMenu', focusInMenu: true});

const view = app.workspace.activeLeaf?.view;
const mode = view.getMode();

if (mode === 'source') {
  // Editing mode - move cursor to last line
  const editor = view.editor;
  const lastLine = editor.lastLine();
  editor.setCursor(lastLine, editor.getLine(lastLine).length);
} else if (mode === 'preview') {
  // Reading mode - scroll to bottom
  const previewElement = view.previewMode?.containerEl || view.containerEl;
  const scrollElement = previewElement.querySelector('.markdown-preview-view') || 
                        previewElement.querySelector('.markdown-reading-view');

  if (scrollElement) {
    scrollElement.scrollTop = scrollElement.scrollHeight;
  }
}

const view = app.workspace.activeLeaf?.view;
const {editor, currentMode} = view;
const lineCount = editor.lineCount();

const clamp = (line, max) => line < 0 ? Math.max(0, max + line + 1) : Math.min(line, max);

const scrollActions = {
  source: (line) => editor.setCursor(clamp(line, lineCount), 0),
  preview: (line) => currentMode.applyScroll(clamp(line, lineCount - 1))
};

scrollActions[view.getMode()]?.(0);

