const wrap = (i, n) => ((i % n) + n) % n;

function navFile(s) {
    const cf = app.workspace.getActiveFile();
    const fs = cf?.parent?.children
        ?.filter(f => !f.children)
        .sort((a, b) => a.basename.localeCompare(b.basename, undefined, {
            numeric: true,
            sensitivity: 'base'
        })) || [];
    const ci = fs.findIndex(f => f.path === cf.path);
    if (fs.length > 1)
        app.workspace.activeLeaf.openFile(fs[wrap(ci + s, fs.length)]);
}

